code = """import pandas as pd
import json

# Load stock info
with open(locals()['var_function-call-15554006225660693874'], 'r') as f:
    stock_info = json.load(f)
info_df = pd.DataFrame(stock_info)
symbol_to_name = dict(zip(info_df['Symbol'], info_df['Company Description']))

batch_keys = [
    'var_function-call-5252800165295206979',
    'var_function-call-13938789385629412319',
    'var_function-call-9874252955779927388',
    'var_function-call-674992420395344703',
    'var_function-call-136058918327425108',
    'var_function-call-11513680232247445373'
]
results = []
for key in batch_keys:
    results.extend(locals()[key])
df = pd.DataFrame(results)
df['UpDays'] = pd.to_numeric(df['UpDays'], errors='coerce')
df['DownDays'] = pd.to_numeric(df['DownDays'], errors='coerce')
df = df.dropna()
df = df[df['UpDays'] > df['DownDays']]

# Create Diff column for tie breaking
df['Diff'] = df['UpDays'] - df['DownDays']

# Sort by UpDays DESC, then Diff DESC
df = df.sort_values(by=['UpDays', 'Diff'], ascending=[False, False])

# Get top 5
top5 = df.head(5)

# Get names
top5_names = [symbol_to_name.get(sym, sym) for sym in top5['Symbol']]

print("__RESULT__:")
print(json.dumps(top5_names))"""

